namespace EvilAliens.Constants;

public static class DevComments
{
	public const string Level1A = "Hello. My name is $TTSNAME.\nI do the voice acting for Revenge of the Evil Aliens.\n\nLet me start off by saying that this has been a great\nproject to be a part of, and that I have grown a lot as an\nactor while working on it.";

	public const string Level1B = "I have with me some notes written by the game's\ndesigner, Harald Maassen, that examine some of the\nmore interesting details of the game.\n\nWhile you play, I will read these notes as a form of\nrunning commentary.";

	public const string Level1C = "Hello and thank you for playing my game.\n\nI hope you enjoy it, I've tried my best to make it a\nchallenging experience for any level of skill.";

	public const string Level1D = "As we're flying over the Earth you'll see two of\nmy main sources of graphics: firstly there's the\nsprites used for the main characters such as the \nplayer's ship and the UFO's.\n\nThose were all made by Danny Holten, a fellow student who\nthese days is working on his doctorate in Computer Graphics.\n\nFor the backdrops we stay in the brainy sector, as those are\nNASA footage of actual stars and planets.";

	public const string Level1E = "The music you're hearing is from UNKLE, and I think it fits\nnicely with the pacing and setting of the game.\n\nI've always thought it a shame that many games have subpar\nmusic, and I enjoyed being able to put my favorite MP3s\nin this.\n\nI guess technically I'm stealing this music, but I don't have\nany moral qualms about it. I'm not making any money on this,\nand I doubt people will download a game just to get a low\nquality and edited version of a song.";

	public const string Level1F = "Cheesy warnings, like the one before the asteroid field,\nare something I wanted to put in the game from the very\nbeginning. Arcade games always seem to be full of them, and\nthat's the sort of atmosphere I've tried to recreate.\n\nThe same could be said about the scoring: the actual score\ndoesn't even do anything, but it's fun seeing those big numbers\nfloat across the screen.";

	public const string Level1G = "Speaking of the combo system. I found that it was a bit\ndisappointing that the game didn't really reward big\ncombos in a meaningful way, so that's how I came up with\nthe power-bar idea.\n\nI already had a few powerups and I thought: what if you\ncould store these powerups and reuse them, and the effect\ngot bigger if you had a big combo going on.";

	public const string Level1H = "Every space shooter needs disembodied brains.\n\nI found the picture on Google and added a glow after seeing\na Futurama episode.\n\nThe inspiration for what these do is obviously Asteroids.\nThey even wrap around the screen, which doesn't make a lot of\nsense considering normal enemies don't.";

	public const string Level1I = "The sounds are all from random free sound effect sites.\n\nI think the splatter sound made by these Brain Spawns is\na guy eating scrunchies, and the explosions are from an old\ndesktop theme.";

	public const string Level1_2A = "And here we encounter one of the problems of the hobbyist:\nIt's hard to find good artwork.\n\nI had to resort to scaling the original UFO sprite to\ncreate these lazer-UFO's. The result looks pixelated,\nbut it does somewhat fit in the cheesy theme we have going.\n\nThe boss UFO is even bigger, and it looks terrible, but I couldn't\nfind anything useful to replace it with.";

	public const string Level1_2B = "The boss started life as an experiment. Just a way to see if\nI could get a big monster in the game that halted progression\nfor a while.\n\nIt sort of grew on me so I put it back into the game, thus\nstarting the two-bosses-per-level setup that all the levels have.";

	public const string Level1_3A = "The final wave of the level is always very hard.\n\nYou may have noticed that the game slowly increases its\ndifficulty as you play, so even if you arrive at this\npoint with a lot of powerups, it will be difficult to\nsurvive.\n\nWhen you die, though, the difficulty resets to its default\nlevel.\n\nWhich is still pretty hard on Hard Mode.";

	public const string Level1_3B = "A problem with difficulty is that I am my main playstester.\n\nI have played this game over and over to test new monsters,\nbugs, etcetera, and as a result I've become quite the pro.\n\nThe game is balanced around me being able to finish it fairly\neasily on Very Hard. Monsters spawn 100%, shoot 100% of the\ntime and move at 100% speed when on Very Hard.\n\nThen I added an extra difficulty level Inzane which is 120%\nthat even I have a hard time beating.";

	public const string Level1_4A = "The final boss is an old design that I created with a friend\nfor an online contest. The idea is that he's very modular and\ncan reappear in multiple levels. In this game he reappears as\nthe subboss for level 3 where he sucks Death Stars instead of\nasteroids.";

	public const string Level1_4B = "This boss has undergone a lot of tweaking. He started off\nbeing very hard, and has been made easier multiple times.\n\nI still think he's probably the hardest boss in the game,\nespecially his incarnation on level 3.";
}
